import{_ as n,C as l,o,c as s,E as i,w as r,a as t,a0 as g}from"./chunks/framework.CkNTPv-z.js";const _=JSON.parse('{"title":"Spain Legal Rights","description":"Legal rights for transgender people in Spain","frontmatter":{"layout":"doc","title":"Spain Legal Rights","description":"Legal rights for transgender people in Spain"},"headers":[],"relativePath":"europe/spain/legal-rights.md","filePath":"europe/spain/legal-rights.md","lastUpdated":null}'),d={name:"europe/spain/legal-rights.md"};function h(c,e,u,p,m,f){const a=l("Badge");return o(),s("div",null,[i(a,{variant:"yellow"},{default:r(()=>[...e[0]||(e[0]=[t("Self-ID since 2023",-1)])]),_:1}),i(a,{variant:"green"},{default:r(()=>[...e[1]||(e[1]=[t("Hate Crime Protections",-1)])]),_:1}),i(a,{variant:"blue"},{default:r(()=>[...e[2]||(e[2]=[t("Comprehensive Anti-Discrimination",-1)])]),_:1}),e[3]||(e[3]=g('<h1 id="legal-rights-in-spain" tabindex="-1">Legal Rights in Spain <a class="header-anchor" href="#legal-rights-in-spain" aria-label="Permalink to &quot;Legal Rights in Spain&quot;">​</a></h1><h2 id="gender-recognition" tabindex="-1">Gender Recognition <a class="header-anchor" href="#gender-recognition" aria-label="Permalink to &quot;Gender Recognition&quot;">​</a></h2><p>The <strong>Law 3/2023</strong> (Ley Trans) allows self-determination of gender:</p><ul><li><strong>Age</strong>: 16+ can self-declare; 12-16 with judicial approval; under 12 requires court order</li><li><strong>Medical Requirements</strong>: None — no diagnosis, surgery, or hormone therapy required</li><li><strong>Process</strong>: Simple administrative declaration at Civil Registry (Registro Civil)</li><li><strong>Timeframe</strong>: 3-4 months typically</li></ul><h2 id="name-changes" tabindex="-1">Name Changes <a class="header-anchor" href="#name-changes" aria-label="Permalink to &quot;Name Changes&quot;">​</a></h2><ul><li>Simple process through the <strong>Civil Registry</strong></li><li>No medical requirements</li><li>Processed alongside gender marker change or separately</li><li>Usually takes 2-4 months</li></ul><h2 id="anti-discrimination-laws" tabindex="-1">Anti-Discrimination Laws <a class="header-anchor" href="#anti-discrimination-laws" aria-label="Permalink to &quot;Anti-Discrimination Laws&quot;">​</a></h2><p>Spain has comprehensive protections at both national and regional levels:</p><ul><li><strong>Employment</strong>: Protected under national labor law</li><li><strong>Housing</strong>: Explicit protections in housing legislation</li><li><strong>Education</strong>: Schools must respect gender identity</li><li><strong>Healthcare</strong>: Access to trans healthcare is a legal right</li><li><strong>Public Services</strong>: Cannot be denied based on gender identity</li></ul><h2 id="regional-variations" tabindex="-1">Regional Variations <a class="header-anchor" href="#regional-variations" aria-label="Permalink to &quot;Regional Variations&quot;">​</a></h2><p>Some autonomous communities have additional protections:</p><ul><li><strong>Catalonia</strong>: Comprehensive LGBT+ law (Law 11/2014)</li><li><strong>Madrid</strong>: Trans-specific healthcare protocols</li><li><strong>Andalusia</strong>: Pioneering trans healthcare since 1999</li><li><strong>Basque Country</strong>: Strong anti-discrimination legislation</li><li><strong>Valencia</strong>: Comprehensive trans rights law</li></ul><h2 id="hate-crime-laws" tabindex="-1">Hate Crime Laws <a class="header-anchor" href="#hate-crime-laws" aria-label="Permalink to &quot;Hate Crime Laws&quot;">​</a></h2><p>Gender identity is explicitly included as a protected characteristic in the Criminal Code.</p><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><ul><li><a href="https://www.igualdad.gob.es/" target="_blank" rel="noreferrer">Ministry of Equality</a></li><li><a href="https://felgtb.com/" target="_blank" rel="noreferrer">FELGTB+</a></li><li><a href="https://chrysallis.es/" target="_blank" rel="noreferrer">Chrysallis (Trans Youth Families)</a></li></ul>',16))])}const C=n(d,[["render",h]]);export{_ as __pageData,C as default};
